#ifdef __cplusplus
struct firewall_bpf *firewall_bpf::open(const struct bpf_object_open_opts *opts) { return firewall_bpf__open_opts(opts); }
struct firewall_bpf *firewall_bpf::open_and_load() { return firewall_bpf__open_and_load(); }
int firewall_bpf::load(struct firewall_bpf *skel) { return firewall_bpf__load(skel); }
int firewall_bpf::attach(struct firewall_bpf *skel) { return firewall_bpf__attach(skel); }
void firewall_bpf::detach(struct firewall_bpf *skel) { firewall_bpf__detach(skel); }
void firewall_bpf::destroy(struct firewall_bpf *skel) { firewall_bpf__destroy(skel); }
const void *firewall_bpf::elf_bytes(size_t *sz) { return firewall_bpf__elf_bytes(sz); }
#endif /* __cplusplus */

__attribute__((unused)) static void
firewall_bpf__assert(struct firewall_bpf *s __attribute__((unused)))
{
#ifdef __cplusplus
#define _Static_assert static_assert
#endif
	_Static_assert(sizeof(s->rodata->need_l4_match) == 1, "unexpected size of 'need_l4_match'");
	_Static_assert(sizeof(s->rodata->blacklist_count) == 4, "unexpected size of 'blacklist_count'");
#ifdef __cplusplus
#undef _Static_assert
#endif
}

